import { ApiProperty } from '@nestjs/swagger';
import { Type } from 'class-transformer';

import {
  AssetEntity,
  AssetExtras,
  AssetHandoverEntity,
  AssetHandoverOption,
  AssetHandoverStatus,
  AssetHandoverType,
  AssetMeta,
  BuybackEntity,
  BuybackOfferEntity,
  BuybackRequestEntity,
  BuybackRequestEvent,
  BuybackRequestStage,
  BuybackRequestStatus,
  BuybackStatus,
  BuybackType,
  CategoryEntity,
  CourierPartnerEntity,
  CustodyEntity,
  CustodyLocationEntity,
} from '@/db';

class CategoryDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'Electronics' })
  name: string;

  static mapFromEntity(entity: CategoryEntity): CategoryDto {
    return {
      id: entity.id,
      name: entity.name,
    };
  }
}

export class AssetHandoverDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({
    enum: AssetHandoverType,
    example: AssetHandoverType.SellerToPlatform,
  })
  type: AssetHandoverType;

  @ApiProperty({
    enum: AssetHandoverStatus,
    example: AssetHandoverStatus.Pending,
  })
  status: AssetHandoverStatus;

  @ApiProperty({
    enum: AssetHandoverOption,
    example: AssetHandoverOption.InPerson,
  })
  option: AssetHandoverOption;

  @ApiProperty()
  @Type(() => CourierPartnerDto)
  courierPartner: CourierPartnerDto | null;

  @ApiProperty({ example: 'TRACK123456' })
  courierNumber: string | null;

  @ApiProperty({ example: '2024-10-15T10:00:00Z' })
  visitDate: Date | null;

  @ApiProperty()
  @Type(() => CustodyLocationDto)
  toCustodyLocation: CustodyLocationDto | null;

  @ApiProperty()
  @Type(() => CustodyLocationDto)
  fromCustodyLocation: CustodyLocationDto | null;

  static mapFromEntity(entity: AssetHandoverEntity): AssetHandoverDto {
    return {
      id: entity.id,
      type: entity.type,
      status: entity.status,
      option: entity.option,
      courierPartner: entity.courierPartner
        ? CourierPartnerDto.mapFromEntity(entity.courierPartner)
        : null,
      courierNumber: entity.courierNumber,
      visitDate: entity.visitDate,
      toCustodyLocation: entity.toCustodyLocation
        ? CustodyLocationDto.mapFromEntity(entity.toCustodyLocation)
        : null,

      fromCustodyLocation: entity.fromCustodyLocation
        ? CustodyLocationDto.mapFromEntity(entity.fromCustodyLocation)
        : null,
    };
  }
}

class AssetDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ type: CategoryDto })
  @Type(() => CategoryDto)
  category: CategoryDto;


  @ApiProperty({
    example: {
      photos: {
        order: ['123e4567-e89b-12d3-a456-426614174000'],
        main: '123e4567-e89b-12d3-a456-426614174000',
      },
    },
  })
  meta: AssetMeta;

  @ApiProperty({
    description: 'Photo file IDs',
    type: [String],
    example: ['123e4567-e89b-12d3-a456-426614174000'],
  })
  photos: string[];

  @ApiProperty()
  declarationFormId: string | null;

  @ApiProperty({ type: AssetHandoverDto })
  @Type(() => AssetHandoverDto)
  handover: AssetHandoverDto | null;

  @ApiProperty()
  podId: string | null;

  @ApiProperty()
  openBoxVideoId: string | null;

  @ApiProperty()
  categoryFields: Record<string, any>;

  @ApiProperty({
    description: 'Additional item details',
    example: { originalBox: true, ownershipDocs: false, authCert: true },
    nullable: true,
  })
  extras: AssetExtras | null;

  static mapFromEntity(entity: AssetEntity): AssetDto {
    const handover = entity.handovers?.find(
      (handover) => handover.type === AssetHandoverType.SellerToPlatform,
    );

    const fields = entity.categoryFields || {};

    return {
      id: entity.id,
      photos: entity.photos.map((photo) => photo.id),
      category: CategoryDto.mapFromEntity(entity.category),
      meta: entity.meta,
      declarationFormId: entity.declarationFormId,
      podId: entity.podId,
      openBoxVideoId: entity.openBoxVideoId,
      handover: handover ? AssetHandoverDto.mapFromEntity(handover) : null,
      categoryFields: fields,
      extras: entity.extras ?? null,
    };
  }
}

class BuybackDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackType, example: BuybackType.Buyback })
  type: BuybackType;

  @ApiProperty({ enum: BuybackStatus, example: BuybackStatus.Quote })
  status: BuybackStatus;

  @ApiProperty({ type: AssetDto })
  @Type(() => AssetDto)
  asset: AssetDto;

  static mapFromEntity(entity: BuybackEntity): BuybackDto {
    return {
      id: entity.id,
      type: entity.type,
      status: entity.status,
      asset: AssetDto.mapFromEntity(entity.asset),
    };
  }
}

class OfferDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'BUYBACK_OFFER' })
  type: string;

  @ApiProperty({
    description: 'Offer data',
    example: { amount: 500, currency: 'USD' },
  })
  data: any;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  expiresAt: Date | null;

  static mapFromEntity(entity: BuybackOfferEntity): OfferDto | null {
    if (!entity) return null;
    return {
      id: entity.id,
      type: entity.type,
      data: entity.data,
      expiresAt: entity.expiresAt,
    };
  }
}

class CourierPartnerDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'DHL' })
  name: string;

  static mapFromEntity(entity: CourierPartnerEntity): CourierPartnerDto | null {
    if (!entity) return null;
    return {
      id: entity.id,
      name: entity.name,
    };
  }
}

class CustodyLocationDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'Main Warehouse' })
  name: string;

  @ApiProperty()
  custody: CustodyDto | null;

  static mapFromEntity(
    entity: CustodyLocationEntity,
  ): CustodyLocationDto | null {
    if (!entity) return null;

    return {
      id: entity.id,
      name: entity.name,
      custody: CustodyDto.mapFromEntity(entity.custody),
    };
  }
}

class CustodyDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'Secure Storage' })
  name: string;

  static mapFromEntity(entity: CustodyEntity): CustodyDto | null {
    if (!entity) return null;
    return {
      id: entity.id,
      name: entity.name,
    };
  }
}

export class BuybackRequestListItemDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackRequestStatus })
  status: BuybackRequestStatus;

  @ApiProperty({ enum: BuybackRequestStage })
  stage: BuybackRequestStage;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  createdAt: Date;

  @ApiProperty({ type: BuybackDto })
  @Type(() => BuybackDto)
  buyback: BuybackDto;

  static mapFromEntity(
    entity: BuybackRequestEntity,
  ): BuybackRequestListItemDto {
    return {
      id: entity.id,
      status: entity.status,
      stage: entity.stage,
      createdAt: entity.createdAt,
      buyback: BuybackDto.mapFromEntity(entity.buyback),
    };
  }
}

export class BuybackRequestDetailDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackRequestStatus })
  status: BuybackRequestStatus;

  @ApiProperty({ enum: BuybackRequestStage })
  stage: BuybackRequestStage;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  createdAt: Date;

  @ApiProperty({ example: 'Rejected due to condition', nullable: true })
  rejectReason?: string;

  @ApiProperty({ type: BuybackDto })
  @Type(() => BuybackDto)
  buyback: BuybackDto;

  @ApiProperty({ type: OfferDto, nullable: true })
  @Type(() => OfferDto)
  preAuthOffer?: OfferDto | null;

  @ApiProperty({ type: OfferDto, nullable: true })
  @Type(() => OfferDto)
  postAuthOffer?: OfferDto | null;

  @ApiProperty({ type: [Object], description: 'Event log entries' })
  eventsLog: BuybackRequestEvent[];

  static mapFromEntity(entity: BuybackRequestEntity): BuybackRequestDetailDto {
    return {
      id: entity.id,
      status: entity.status,
      stage: entity.stage,
      createdAt: entity.createdAt,
      rejectReason: entity.rejectReason,
      buyback: BuybackDto.mapFromEntity(entity.buyback),
      preAuthOffer: entity.preAuthOffer
        ? OfferDto.mapFromEntity(entity.preAuthOffer)
        : null,
      postAuthOffer: entity.postAuthOffer
        ? OfferDto.mapFromEntity(entity.postAuthOffer)
        : null,
      eventsLog: entity.eventsLog?.data || [],
    };
  }
}

