import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { Type } from 'class-transformer';

import {
  AssetEntity,
  AssetHandoverType,
  AssetStatus,
  BuybackComputedDetails,
  BuybackEntity,
  BuybackExtensionEntity,
  BuybackExtensionType,
  BuybackOfferEntity,
  BuybackRequestStage,
  BuybackRequestStatus,
  BuybackStatus,
  BuybackType,
} from '@/db';
import { AssetHandoverDto } from '@/api/app/buyback-requests/dtos';

class AssetCategoryDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'Electronics' })
  name: string;

  static mapFromEntity(entity: any): AssetCategoryDto {
    return {
      id: entity.id,
      name: entity.name,
    };
  }
}


class OfferDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 'BUYBACK_OFFER' })
  type: string;

  @ApiProperty({
    description: 'Offer data',
    example: { amount: 500, currency: 'USD' },
  })
  data: any;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  expiresAt: Date | null;

  static mapFromEntity(entity: BuybackOfferEntity): OfferDto | null {
    if (!entity) return null;
    return {
      id: entity.id,
      type: entity.type,
      data: entity.data,
      expiresAt: entity.expiresAt,
    };
  }
}

class BuybackAssetDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: AssetStatus, example: AssetStatus.InCustody })
  status: AssetStatus;

  @ApiProperty({ example: { storage: '256GB', color: 'Space Gray' } })
  categoryFields: Record<string, any>;


  @ApiProperty({ example: { warranty: true, originalBox: true } })
  extras: Record<string, any>;

  @ApiProperty({
    type: [String],
    example: ['123e4567-e89b-12d3-a456-426614174000'],
  })
  photos: string[];

  @ApiProperty({ example: { notes: 'Excellent condition' } })
  meta: Record<string, any>;

  @ApiProperty({ type: AssetCategoryDto })
  @Type(() => AssetCategoryDto)
  category: AssetCategoryDto;

  @ApiProperty()
  declarationFormId: string | null;

  @ApiProperty({ nullable: true })
  additionalDetails: string | null;

  static mapFromEntity(entity: AssetEntity): BuybackAssetDto {

    const fields = entity.categoryFields || {};

    return {
      id: entity.id,
      status: entity.status,
      categoryFields: fields,
      extras: entity.extras || {},
      photos: Array.isArray(entity.photos) ? entity.photos.map((p) => p.id) : [],
      meta: entity.meta || {},
      category: entity.category ? AssetCategoryDto.mapFromEntity(entity.category) : null,
      declarationFormId: entity.declarationFormId,
      additionalDetails: entity.additionalDetails ?? null,
    } as BuybackAssetDto;
  }
}

class BuybackRequestDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackRequestStatus })
  status: BuybackRequestStatus;

  @ApiProperty({ enum: BuybackRequestStage })
  stage: BuybackRequestStage;

  @ApiProperty({ type: OfferDto, nullable: true })
  @Type(() => OfferDto)
  preAuthOffer?: OfferDto | null;

  @ApiProperty({ type: OfferDto, nullable: true })
  @Type(() => OfferDto)
  postAuthOffer?: OfferDto | null;

  @ApiProperty({
    description: 'Events log',
    type: 'array',
    items: { type: 'object' },
  })
  eventsLog: Array<{
    status: BuybackRequestStatus;
    stage: BuybackRequestStage;
    timestamp: Date;
  }>;

  static mapFromEntity(entity: any): BuybackRequestDto | null {
    if (!entity) return null;
    return {
      id: entity.id,
      status: entity.status,
      stage: entity.stage,
      preAuthOffer: entity.preAuthOffer
        ? OfferDto.mapFromEntity(entity.preAuthOffer)
        : null,
      postAuthOffer: entity.postAuthOffer
        ? OfferDto.mapFromEntity(entity.postAuthOffer)
        : null,
      eventsLog: entity.eventsLog?.data || [],
    };
  }
}

class ExtensionDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ example: 1 })
  month: number;

  @ApiProperty({ enum: BuybackExtensionType })
  type: BuybackExtensionType;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  startDate: Date;

  @ApiProperty({ example: '2024-11-07T10:00:00Z' })
  endDate: Date;

  static mapFromEntity(entity: BuybackExtensionEntity): ExtensionDto {
    return {
      id: entity.id,
      month: entity.month,
      type: entity.type,
      startDate: entity.startDate,
      endDate: entity.endDate,
    };
  }
}

class BuybackRequestEventDto {
  @ApiProperty({ enum: BuybackRequestStatus })
  status: BuybackRequestStatus;

  @ApiProperty({ enum: BuybackRequestStage })
  stage: BuybackRequestStage;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  timestamp: Date;
}

export class BuybackResponseDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackType, example: BuybackType.Buyback })
  type: BuybackType;

  @ApiProperty({ enum: BuybackStatus, example: BuybackStatus.Quote })
  status: BuybackStatus;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  createdAt: Date;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  updatedAt: Date;

  @ApiProperty({ type: BuybackAssetDto })
  @Type(() => BuybackAssetDto)
  asset: BuybackAssetDto;

  @ApiProperty({
    description: 'Events log from associated request',
    type: [BuybackRequestEventDto],
    required: false,
  })
  @Type(() => BuybackRequestEventDto)
  eventsLog?: BuybackRequestEventDto[];

  @ApiProperty({ type: BuybackRequestDto, nullable: true })
  @Type(() => BuybackRequestDto)
  request?: BuybackRequestDto | null;

  @ApiProperty({ type: [ExtensionDto], nullable: true })
  @Type(() => ExtensionDto)
  extensions?: ExtensionDto[] | null;

  @ApiProperty()
  computedDetails: BuybackComputedDetails | null;

  @ApiProperty({ type: AssetHandoverDto, nullable: true })
  @Type(() => AssetHandoverDto)
  handover?: AssetHandoverDto | null;

  static mapFromEntity(entity: BuybackEntity): BuybackResponseDto {
    const handover = entity.asset?.handovers?.find(
      (handover) => handover.type === AssetHandoverType.PlatformToSeller,
    );

    return {
      id: entity.id,
      type: entity.type,
      status: entity.status,
      createdAt: entity.createdAt,
      updatedAt: entity.updatedAt,
      asset: BuybackAssetDto.mapFromEntity(entity.asset),
      eventsLog: entity.request?.eventsLog?.data || [],
      request: BuybackRequestDto.mapFromEntity(entity.request),
      computedDetails: entity.computedDetails,
      handover: handover ? AssetHandoverDto.mapFromEntity(handover) : null,
      extensions: entity.extensions
        ? entity.extensions.map((ext) => ExtensionDto.mapFromEntity(ext))
        : null,
    };
  }
}

export class BuybackListItemDto {
  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
  id: string;

  @ApiProperty({ enum: BuybackType, example: BuybackType.Buyback })
  type: BuybackType;

  @ApiProperty({ enum: BuybackStatus, example: BuybackStatus.Quote })
  status: BuybackStatus;

  @ApiProperty({ example: '2024-10-08T10:00:00Z' })
  createdAt: Date;

  @ApiProperty({ type: BuybackAssetDto })
  @Type(() => BuybackAssetDto)
  asset: BuybackAssetDto;

  @ApiProperty({ type: BuybackRequestDto, nullable: true })
  @Type(() => BuybackRequestDto)
  request?: BuybackRequestDto | null;

  static mapFromEntity(entity: BuybackEntity): BuybackListItemDto {
    return {
      id: entity.id,
      type: entity.type,
      status: entity.status,
      createdAt: entity.createdAt,
      asset: BuybackAssetDto.mapFromEntity(entity.asset),
      request: BuybackRequestDto.mapFromEntity(entity.request),
    };
  }
}

export class BuybackListResponseDto {
  @ApiProperty({ type: [BuybackListItemDto] })
  @Type(() => BuybackListItemDto)
  data: BuybackListItemDto[];

  @ApiProperty({ example: 100 })
  total: number;

  @ApiProperty({ example: 0 })
  skip: number;

  @ApiProperty({ example: 20 })
  take: number;

  static mapFromEntity(result: {
    data: BuybackEntity[];
    total: number;
    skip: number;
    take: number;
  }): BuybackListResponseDto {
    return {
      data: result.data.map((item) => BuybackListItemDto.mapFromEntity(item)),
      total: result.total,
      skip: result.skip,
      take: result.take,
    };
  }
}

export class RenewBuybackResponseDto {
  @ApiProperty({
    description: 'Payment status',
    enum: ['succeeded', 'pending'],
    example: 'succeeded',
  })
  status: 'succeeded' | 'pending';

  @ApiPropertyOptional({
    description: 'PayPal approval URL (for PayPal payments)',
    example: 'https://www.paypal.com/checkoutnow?token=...',
  })
  approveUrl?: string;

  @ApiPropertyOptional({
    description: 'Crypto payment address (for NOWPayments)',
    example: 'TXvZ...',
  })
  paymentAddress?: string;

  @ApiPropertyOptional({
    description: 'NOWPayments payment ID for status polling',
    example: 123456789,
  })
  nowpaymentsId?: number;
}

