1	import { ApiProperty } from '@nestjs/swagger';
2	
3	import {
4	  AssetEntity,
5	  AssetHandoverEntity,
6	  AssetHandoverOption,
7	  AssetHandoverStatus,
8	  AssetHandoverType,
9	  AssetMeta,
