20	  BuybackType,
21	  CategoryEntity,
22	  CourierPartnerEntity,
23	  CustodyLocationEntity,
24	} from '@/db';
25	import { Type } from 'class-transformer';
26	import { UserDto } from '@/api/admin';
27	import { AssetCondition } from '../../../../db/entities/enums/asset-condition.enum';
28	
29	class CategoryDto {
30	  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
31	  id: string;
32	
33	  @ApiProperty({ example: 'Electronics' })
34	  name: string;
35	
36	  static mapFromEntity(entity: CategoryEntity): CategoryDto {
37	    return {
38	      id: entity.id,
39	      name: entity.name,
40	    };
41	  }
42	}
43	
44	class AssetDto {
45	  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000' })
46	  id: string;
47	
48	  @ApiProperty({ type: CategoryDto })
49	  @Type(() => CategoryDto)
50	  category: CategoryDto;
51	
52	  @ApiProperty()
53	  declarationFormId: string | null;
54	
55	  @ApiProperty()
56	  podId: string | null;
57	
58	  @ApiProperty()
59	  openBoxVideoId: string | null;
60	
61	  @ApiProperty({
62	    example: {
63	      photos: {
64	        order: ['123e4567-e89b-12d3-a456-426614174000'],
65	        main: '123e4567-e89b-12d3-a456-426614174000',
66	      },
67	    },
68	  })
69	  meta: AssetMeta;
70	
71	  @ApiProperty({
72	    description: 'Photo file IDs',
73	    type: [String],
74	    example: ['123e4567-e89b-12d3-a456-426614174000'],
75	  })
76	  photos: string[];
77	
78	  @ApiProperty()
79	  @Type(() => AdminAssetHandoverDto)
80	  handover: AdminAssetHandoverDto | null;
81	
82	  @ApiProperty()
83	  categoryFields: Record<string, any>;
84	
85	
86	  static mapFromEntity(entity: AssetEntity): AssetDto {
87	    const handover = entity.handovers?.find(
88	      (handover) => handover.type === AssetHandoverType.SellerToPlatform,
89	    );
90	
91	    const fields = entity.categoryFields || {};
92	
93	    return {
94	      id: entity.id,
95	      photos: entity.photos ? entity.photos.map((photo) => photo.id) : [],
96	      category: CategoryDto.mapFromEntity(entity.category),
97	      meta: entity.meta,
98	      declarationFormId: entity.declarationFormId,
99	      podId: entity.podId,
100	      openBoxVideoId: entity.openBoxVideoId,
101	      handover: handover ? AdminAssetHandoverDto.mapFromEntity(handover) : null,
102	      categoryFields: fields,
103	    };
