import {
  Column,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  OneToMany,
  OneToOne,
} from 'typeorm';

import { BaseEntity } from '../utils';
import { CategoryEntity } from './category.entity';
import { FileEntity } from './file.entity';
import { BuybackEntity } from './buyback.entity';
import { UserEntity } from './user.entity';
import { AssetValuationEntity } from './asset-valuation.entity';
import { AssetHandoverEntity } from './asset-handover.entity';
import { CustodyLocationEntity } from './custody-location.entity';


export interface AssetMeta {
  photos?: {
    order: string[];
    main: string;
  } | null;
  authPhotos?: {
    order: string[];
    main: string;
  } | null;
}

export enum AssetExtraItem {
  OriginalBox = 'originalBox',
  OwnershipDocs = 'ownershipDocs',
  AuthCert = 'authCert',
  SignedByArtist = 'signedByArtist',
}

export type AssetExtras = Record<AssetExtraItem, boolean>;

// Record<fieldId, answer>
export type AssetCategoryFields = Record<string, any>;

export enum AssetStatus {
  // Hidden in admin
  Created = 'CREATED',

  // Active
  Delivering = 'DELIVERING', // actions: DELIVERY_INFO, CONFIRM_HANDOVER
  InCustody = 'IN_CUSTODY', // actions: none

import { ApiProperty } from '@nestjs/swagger';
import {
  IsArray,
  IsBoolean,
  IsDate,
  IsEnum,
  IsNotEmpty,
  IsNumber,
  IsObject,
  IsOptional,
  IsString,
  IsUUID,
  ValidateNested,
} from 'class-validator';
import { Transform, Type } from 'class-transformer';

import {
  AssetExtras,
  AssetHandoverOption,
  BuybackType,
} from '@/db';
import { TransformBooleanString } from '@/common';
import { AssetCondition } from '@/db/entities/enums/asset-condition.enum';

class PhotosMetaDto {
  @ApiProperty({
    description: 'Photo order',
    type: [String],
    example: ['123e4567-e89b-12d3-a456-426614174000'],
  })
  @IsArray()
  @IsUUID('4', { each: true })
  order: string[];

  @ApiProperty({
    description: 'Main photo',
    example: '123e4567-e89b-12d3-a456-426614174000',
    required: false,
  })
  @IsUUID()
  main: string;
}

class AssetExtrasDto implements AssetExtras {
  @IsBoolean()
  @IsNotEmpty()
  originalBox: boolean;

  @IsBoolean()
  @IsNotEmpty()
  ownershipDocs: boolean;

  @IsBoolean()
  @IsNotEmpty()
  authCert: boolean;

  @IsBoolean()
  @IsNotEmpty()
  signedByArtist: boolean;
}

class AssetMetaDto {
  @ApiProperty({
    description: 'Photo metadata',
    type: PhotosMetaDto,
  })
  @IsOptional()
  @ValidateNested()
  @Type(() => PhotosMetaDto)
  photos: PhotosMetaDto;
}

export class CreateBuybackAssetDto {
  @ApiProperty({
    description: 'Category-specific fields',
    example: {
      year: 2023,
      condition: 'MINT',
      modelNumber: 'A2484',
      storage: '256GB'
    },
  })
  @IsObject()
  @IsNotEmpty()
  categoryFields: Record<string, any>;

  @ApiProperty({
    description: 'Category ID',
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsNotEmpty()
  categoryId: string;

  @ApiProperty({
    description: 'Asset extras',
    example: { originalBox: true, ownershipDocs: true, authCert: false },
  })
  @ValidateNested()
  @Type(() => AssetExtrasDto)
  @IsNotEmpty()
  extras: AssetExtrasDto;

  @ApiProperty({
    description: 'Photo file IDs',
    type: [String],
    example: ['123e4567-e89b-12d3-a456-426614174000'],
  })
  @IsArray()
  @IsUUID('4', { each: true })
  photos: string[];

  @ApiProperty({
    description: 'Asset metadata',
    example: {
      photos: {
        order: ['123e4567-e89b-12d3-a456-426614174000'],
        main: '123e4567-e89b-12d3-a456-426614174000',
      },
    },
  })
  @ValidateNested()
  @Type(() => AssetMetaDto)
  @IsNotEmpty()
  meta: AssetMetaDto;

  @ApiProperty({
    description: 'Additional details about the asset',
    example: 'Limited edition, purchased directly from the gallery.',
    required: false,
  })
  @IsString()
  @IsOptional()
  additionalDetails?: string | null;
}

export class CreateBuybackRequestDto {
  @ApiProperty({
    description: 'Asset details',
    type: CreateBuybackAssetDto,
  })
  @ValidateNested()
  @Type(() => CreateBuybackAssetDto)
  @IsNotEmpty()
  asset: CreateBuybackAssetDto;

  @ApiProperty({
    description: 'Buyback type',
    enum: BuybackType,
    example: BuybackType.Buyback,
  })
  @IsEnum(BuybackType)
  @IsNotEmpty()
  type: BuybackType;
}

export class BuybackFiltersDto {
  @ApiProperty({
    description: 'Search query for asset name, brand, model, or category',
    required: false,
    example: 'iPhone',
  })
  @IsString()
  @IsOptional()
  search?: string;

  @ApiProperty({
    description: 'Filter by category IDs',
    required: false,
    type: [String],
    example: ['123e4567-e89b-12d3-a456-426614174000'],
  })
  @IsUUID('4', { each: true })
  @IsOptional()
  @Transform(({ value }) => (Array.isArray(value) ? value : [value]))
  categories?: string[];

  @ApiProperty({
    description: 'Filter by buyback types',
    required: false,
    enum: BuybackType,
    isArray: true,
    example: [BuybackType.Buyback],
  })
  @IsEnum(BuybackType, { each: true })
  @IsOptional()
  @Transform(({ value }) => (Array.isArray(value) ? value : [value]))
  types?: BuybackType[];

  @ApiProperty({
    description: 'Filter by active status',
    required: false,
    example: true,
  })
  @TransformBooleanString()
  @IsBoolean()
  active: boolean;
}

export class RenewBuybackRequestDto {
  @ApiProperty({
    description: 'Stripe saved payment method ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  stripeMethodId?: string;

  @ApiProperty({
    description: 'PayPal saved payment method ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  paypalMethodId?: string;

  @ApiProperty({
    description: 'Crypto address ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  cryptoAddressId?: string;

  @ApiProperty({
    description: 'Override URL to redirect user after PayPal approval',
    required: false,
    example: 'https://app.example.com/buybacks/abc123?paypal_renewal=success',
  })
  @IsString()
  @IsOptional()
  paypalReturnUrl?: string;

  @ApiProperty({
    description: 'Override URL to redirect user after PayPal cancellation',
    required: false,
    example: 'https://app.example.com/buybacks/abc123',
  })
  @IsString()
  @IsOptional()
  paypalCancelUrl?: string;
}

export class RequestFinalExtensionDto {}

export class PayFinalExtensionDto {
  @ApiProperty({
    description: 'Stripe saved payment method ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  stripeMethodId?: string;

  @ApiProperty({
    description: 'PayPal saved payment method ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  paypalMethodId?: string;

  @ApiProperty({
    description: 'Crypto address ID',
    required: false,
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsUUID()
  @IsOptional()
  cryptoAddressId?: string;

  @ApiProperty({
    description: 'Override URL to redirect user after PayPal approval',
    required: false,
    example: 'https://app.example.com/buybacks/abc123?paypal_renewal=success',
  })
  @IsString()
  @IsOptional()
  paypalReturnUrl?: string;

  @ApiProperty({
    description: 'Override URL to redirect user after PayPal cancellation',
    required: false,
    example: 'https://app.example.com/buybacks/abc123',
  })
  @IsString()
  @IsOptional()
  paypalCancelUrl?: string;
}

export class ReturnAssetRequestDto {
  @ApiProperty({
    description: 'Asset handover option',
    enum: AssetHandoverOption,
    example: AssetHandoverOption.InPerson,
  })
  @IsEnum(AssetHandoverOption)
  @IsNotEmpty()
  assetHandoverOption: AssetHandoverOption;

  @ApiProperty({
    description: 'Visit date for inspection',
    example: '2024-10-15T10:00:00Z',
    required: false,
  })
  @IsDate()
  @IsOptional()
  visitDate?: Date;
}

