  categoryFields: AssetCategoryFields;
  categoryId: string;
  extras: AssetExtras;
  photos: string[];
  meta: AssetMeta;
  additionalDetails?: string | null;
}

export enum AssetSearchType {
  InCustody = 'in-custody',
  Released = 'released',
}

export interface AssetSearchFilters {
  search?: string;
  type: AssetSearchType;
  categories?: string[];
  brands?: string[];
  models?: string[];
  buybackType?: BuybackType;
  assetStatuses?: AssetStatus[];
  custodyLocations?: string[];
  actions?: AssetAction[];
}

